const maxStr = (str, limit = 5000) => {
  if (!str) return '';
  if (str.length <= limit) return str;
  return str.substring(0, limit) + '... [TRUNCATED]';
};

const postsRows = $('Get Latest Posts').all();
const likesRows = $('Get Post Likes').all();
const commentsRows = $('Get Post Comments').all();
const messagesRows = $('Get Recent Messages').all();
const invitationsRows = $('Get Recent Invitations').all();
const outboundRows = $('Get Our Outbound Activity').all();
const substackRows = $('Get Our Substack Posts').all();

let text = 'LINKEDIN & CONTENT MARKETING ACTIVITY REPORT FOR DON JIMMY\n\n';
let refMap = {};
let refCounter = 1;

// 1. Map comments and likes to posts
const posts = {};
postsRows.forEach(row => {
  const p = row.json;
  if (!p.post_id) return;
  posts[p.post_id] = {
    content: maxStr(p.post_content, 3000),
    url: p.post_url,
    published_at: p.post_published_at,
    likes_count: 0,
    comments: []
  };
});

likesRows.forEach(row => {
  const l = row.json;
  if (posts[l.post_id]) {
    posts[l.post_id].likes_count++;
  }
});

commentsRows.forEach(row => {
  const c = row.json;
  if (posts[c.post_id]) {
    posts[c.post_id].comments.push({
      author: c.comment_author,
      content: maxStr(c.comment_content, 1000),
      published_at: c.comment_published_at
    });
  }
});

// 2. Format Posts & Comments Received
text += '=== LATEST PUBLISHED POSTS & INBOUND ENGAGEMENT ===\n';
if (Object.keys(posts).length === 0) {
  text += 'No posts published in the last 7 days.\n\n';
} else {
  Object.entries(posts).forEach(([pId, post]) => {
    const refId = refCounter++;
    const snippet = (post.content || '').substring(0, 40).replace(/\n/g, ' ') || 'LinkedIn Post';
    refMap[String(refId)] = { title: snippet, url: post.url || '' };

    text += `[Post #${refId}] | Likes Received: ${post.likes_count} | Published: ${post.published_at}\n`;
    text += `Content: ${post.content || 'No content'}\n`;
    if (post.comments.length > 0) {
      text += `Comments Received:\n`;
      post.comments.forEach(comment => {
        text += `  - by ${comment.author}: ${comment.content}\n`;
      });
    }
    text += '\n';
  });
}

// 3. Format Outbound Activity
text += '=== OUTBOUND ENGAGEMENT (My Likes & Comments on LinkedIn) ===\n';
if (outboundRows.length === 0 || !outboundRows[0].json.type) {
  text += 'No outbound likes or comments in the last 7 days.\n\n';
} else {
  outboundRows.forEach(row => {
    const act = row.json;
    if (act.type === 'comment') {
      text += `- Commented on post (ID: ${act.post_id}) at ${act.published_at}: \"${maxStr(act.content, 1000)}\"\n`;
    } else {
      text += `- Liked post (ID: ${act.post_id}) at ${act.published_at}\n`;
    }
  });
  text += '\n';
}

// 4. Format Messages
text += '=== DIRECT MESSAGES (Last 7 Days) ===\n';
if (messagesRows.length === 0 || !messagesRows[0].json.sender_name) {
  text += 'No new inbox messages.\n\n';
} else {
  messagesRows.forEach(row => {
    const msg = row.json;
    text += `From: ${msg.sender_name} (Profile URL: ${msg.sender_profile_url || 'N/A'}) | To: ${msg.recipient_name} | Sent: ${msg.sent_at}\n`;
    text += `Message: ${maxStr(msg.content, 2000) || 'No content'}\n\n`;
  });
}

// 5. Format Connection Requests
text += '=== CONNECTION INVITATIONS (Last 7 Days) ===\n';
if (invitationsRows.length === 0 || !invitationsRows[0].json.from_name) {
  text += 'No new connection requests.\n\n';
} else {
  invitationsRows.forEach(row => {
    const invite = row.json;
    const profileUrl = invite.direction === 'INCOMING' ? invite.inviter_profile_url : invite.invitee_profile_url;
    text += `Direction: ${invite.direction} | From: ${invite.from_name} (Profile URL: ${profileUrl || 'N/A'}) | To: ${invite.to_name} | Sent: ${invite.sent_at}\n`;
    if (invite.message) {
      text += `Personal Note: ${invite.message}\n`;
    }
    text += '\n';
  });
}

// 6. Format Substack Posts
text += '=== OUR SUBSTACK BLOG POSTS (Last 7 Days) ===\n';
if (substackRows.length === 0 || !substackRows[0].json.post_title) {
  text += 'No Substack posts published in the last 7 days.\n\n';
} else {
  substackRows.forEach(row => {
    const post = row.json;
    text += `- Title: ${post.post_title} | Published: ${post.post_published_at} | URL: ${post.post_url || 'N/A'}\n`;
    if (post.post_content) {
      text += `  Content: ${maxStr(post.post_content, 6000)}\n`;
    }
  });
  text += '\n';
}

const fs = require('fs');
let persona = '';
try {
  persona = fs.readFileSync('/etc/n8n/agents/giusy.md', 'utf8');
} catch (e) {
  persona = 'Warm, brilliant AI Marketing Director named Giusy.';
}

let strategy = '';
try {
  strategy = fs.readFileSync('/etc/n8n/workflows/prompts/content_strategy.md', 'utf8');
} catch (e) {
  strategy = '';
}

let positioning = '';
try {
  positioning = fs.readFileSync('/etc/n8n/workflows/prompts/usp_market_positioning.md', 'utf8');
} catch (e) {
  positioning = '';
}

const commentsList = [];
commentsRows.forEach(row => {
  const c = row.json;
  const parentPost = posts[c.post_id];
  if (c.comment_content && parentPost && parentPost.url) {
    commentsList.push({
      author: c.comment_author,
      content: maxStr(c.comment_content, 1000),
      post_url: parentPost.url
    });
  }
});

const messagesList = [];
messagesRows.forEach(row => {
  const m = row.json;
  if (m.sender_name && m.sender_profile_url) {
    messagesList.push({
      sender_name: m.sender_name,
      sender_profile_url: m.sender_profile_url
    });
  }
});

const invitationsList = [];
invitationsRows.forEach(row => {
  const inv = row.json;
  if (inv.direction === 'INCOMING' && inv.from_name && inv.inviter_profile_url) {
    invitationsList.push({
      from_name: inv.from_name,
      inviter_profile_url: inv.inviter_profile_url
    });
  } else if (inv.direction === 'OUTGOING' && inv.to_name && inv.invitee_profile_url) {
    invitationsList.push({
      from_name: inv.to_name,
      inviter_profile_url: inv.invitee_profile_url
    });
  }
});

return [{ json: { text: text.substring(0, 500000), ref_map: refMap, giusy_persona: persona, content_strategy: strategy, usp_positioning: positioning, comments_list: commentsList, messages_list: messagesList, invitations_list: invitationsList } }];

